(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[880],{9021:function(e,t,i){Promise.resolve().then(i.bind(i,9564))},9564:function(e,t,i){"use strict";i.r(t),i.d(t,{default:function(){return r}});var a=i(7821),o=i(8078),s=i(3197);let n={slug:"weight-loss",title:"Your Weight Loss Program",subtitle:"Buffington Family Medicine",accentColor:"#0ea5e9",accentColorLight:"#e0f2fe",heroDescription:"Welcome to your personalized weight loss program. This hub is your go-to resource for medication guidance, nutrition tips, exercise plans, and milestone tracking throughout your journey with us.",navItems:[{id:"guide",label:"Guide"},{id:"overview",label:"Overview"},{id:"quick-start",label:"Quick Start"},{id:"start",label:"Start Here"},{id:"how-it-works",label:"How It Works"},{id:"medications",label:"Medications"},{id:"nutrition",label:"Nutrition"},{id:"food-list",label:"Food List"},{id:"meal-plans",label:"Meal Plans"},{id:"vitamins",label:"Vitamins"},{id:"exercise",label:"Exercise"},{id:"milestones",label:"Milestones"},{id:"side-effects",label:"Side Effects"},{id:"common-mistakes",label:"Common Mistakes"},{id:"plateau",label:"Plateaus"},{id:"faqs",label:"FAQs"},{id:"resources",label:"Resources"},{id:"updates",label:"Updates"},{id:"next-steps",label:"Next Steps"}],sections:[{id:"guide",title:"",content:[{type:"callout",variant:"info",title:"How to use this page",body:"Start with the **Quick Start** and **Start Here** sections to get oriented. Jump to **FAQs** any time you have a question. The **Side Effects** section covers what to watch for. Come back to this page as an ongoing reference throughout your program — we update it regularly."}]},{id:"overview",title:"Program Overview",content:[{type:"text",body:"At **Buffington Family Medicine**, our medically supervised weight loss program combines **GLP-1 receptor agonist medications** with nutrition coaching, exercise guidance, and regular follow-up visits to help you reach a healthier weight safely."},{type:"heading",level:3,text:"Most Important Things to Know"},{type:"bullets",items:["**Your first step** is to pick up your medication, choose your injection day, and review the Start Here section","**Mild nausea and appetite changes are normal** — they usually improve within 1-2 weeks","**Monthly visits are required** — you must be seen every 4 weeks to get your medication refilled","**Protein and hydration are your top priorities** — aim for 60-80g protein and 64oz water daily","**Call our office at (817) 431-9199** if you have side effects that concern you or cannot keep food down"]},{type:"callout",variant:"urgent",title:"When to call us",body:"Call **(817) 431-9199** right away if you experience severe or persistent vomiting, severe abdominal pain, signs of an allergic reaction (swelling, rash, difficulty breathing), a lump or swelling in your neck, or new/worsening depression. Full details are in the **Side Effects** section below."},{type:"bullets",items:["**Personalized dosing** — your medication is titrated based on your response and tolerance","**Monthly office visits required** — you must be seen every 4 weeks to get your medication refilled","**Nutrition + exercise support** — practical guidance you can actually follow","**Lab monitoring** — kidney function, thyroid, and metabolic panels tracked throughout","**Safety screenings** — EKG and cardiac history reviewed before starting"]},{type:"callout",variant:"info",title:"What to expect",body:"Most patients begin to notice reduced appetite within the first 1-2 weeks. Meaningful weight loss typically begins by weeks 3-4. Your provider will adjust your dose gradually to maximize results while minimizing side effects."}]},{id:"quick-start",title:"Quick-Start Summary",content:[{type:"text",body:"Here is a compact overview of everything you need to know for your first month. Each topic is covered in detail further down this page."},{type:"heading",level:3,text:"This Week"},{type:"numbered",items:["**Pick up your medication** and store it in the refrigerator","**Choose your injection day** — same day each week, set a reminder","**Give your first injection** following the instructions in Start Here","**Start hitting your protein goal** — 60-80 grams per day","**Drink at least 64 oz of water** every day"]},{type:"heading",level:3,text:"What to Expect: Weeks 1-4"},{type:"bullets",items:["**Week 1:** Appetite may decrease within a few days. Mild nausea is common and usually passes.","**Weeks 2-3:** You will naturally start eating smaller portions. Early side effects begin to improve.","**Week 4:** First follow-up visit. Your provider may increase your dose. Typical weight loss: **3-6 lbs**."]},{type:"heading",level:3,text:"Key Nutrition Priorities"},{type:"bullets",items:["**Protein first** at every meal — chicken, fish, eggs, Greek yogurt","**Stay hydrated** — 64 oz water minimum, set reminders","**Eat slowly and stop when satisfied** — do not wait until you feel full","**Avoid greasy and fried foods** early on to reduce nausea"]},{type:"heading",level:3,text:"Common Early Side Effects"},{type:"bullets",items:["Mild nausea (usually improves in 1-2 weeks)","Constipation (increase water and fiber)","Fatigue (ensure adequate protein intake)","Headache (often related to dehydration)"]},{type:"callout",variant:"info",title:"What is normal in the first month",body:"Mild nausea, appetite changes, occasional constipation, and scale fluctuations are all normal in the first month. Your body is adjusting to the medication. These side effects typically improve as your system adapts, and your provider may adjust your dose at your 4-week follow-up."}]},{id:"start",title:"Start Here: Your First 30 Days",content:[{type:"text",body:"The first month sets the foundation for your success. **Your first step is** picking up your medication and choosing your injection day. **Your next step is** giving your first injection and beginning to track your meals."},{type:"numbered",items:["**Pick up your medication** from the pharmacy and store it in the refrigerator","**Choose your injection day** — pick the same day each week and set a recurring reminder","**Take your starting dose** as directed by your provider (see injection instructions below)","**Begin tracking your meals** — focus on protein intake and hydration","**Weigh yourself weekly** on the same day, at the same time, in the same clothing","**Schedule your 4-week follow-up** if you haven't already","**Call our office** if you experience any side effects that concern you"]},{type:"heading",level:3,text:"Injection Basics"},{type:"text",body:"Inject into your abdomen, thigh, or upper arm. Rotate sites each week. Let the medication come to room temperature for 15-30 minutes before injecting."},{type:"text",body:"Pinch the skin, insert the needle at a 90-degree angle, and inject slowly. Hold for 10 seconds before removing. A slight sting or minor redness at the injection site is normal."},{type:"heading",level:3,text:"Your First Week Priorities"},{type:"bullets",items:["**Hydration goal:** aim for at least 64 oz of water daily","**Protein goal:** 60-80 grams of protein per day from the start","**Eat slowly** — your appetite will decrease; stop when you feel satisfied, not full","**Avoid high-fat and greasy foods** during the first few weeks to reduce nausea"]}]},{id:"how-it-works",title:"How GLP-1 Medications Work",content:[{type:"text",body:"GLP-1 receptor agonists mimic a natural hormone your body produces after eating. They work through **multiple pathways** to support weight loss."},{type:"heading",level:3,text:"Appetite Reduction"},{type:"text",body:"GLP-1 medications act on receptors in the brain that regulate hunger and satiety. You will feel **full sooner** and **satisfied longer** after meals, making it easier to eat less without feeling deprived."},{type:"heading",level:3,text:"Slowed Gastric Emptying"},{type:"text",body:"These medications slow how quickly food leaves your stomach. This means you feel full for a longer period after eating, and blood sugar spikes after meals are reduced."},{type:"heading",level:3,text:"Hormonal & Metabolic Effects"},{type:"bullets",items:["**Insulin regulation** — improves how your body handles blood sugar","**Glucagon suppression** — reduces sugar released by the liver between meals","**Reward signaling** — reduces food cravings and the urge to overeat","**Inflammation** — emerging research suggests GLP-1s may reduce systemic inflammation"]},{type:"callout",variant:"info",title:"Dual-agonist medications",body:"Tirzepatide (Mounjaro/Zepbound) targets both GLP-1 and GIP receptors, which may provide additional metabolic benefits and slightly greater average weight loss compared to GLP-1-only medications like semaglutide."}]},{id:"medications",title:"GLP-1 Medications",content:[{type:"text",body:"At Buffington Family Medicine, we prescribe FDA-approved GLP-1 receptor agonists for weight management. Your provider will choose the best option based on your health history, insurance coverage, and treatment goals."},{type:"table",headers:["Medication","Brand Names","Type","Frequency","Starting Dose"],rows:[["Semaglutide","Wegovy, Ozempic","GLP-1","Weekly injection","0.25 mg"],["Tirzepatide","Zepbound, Mounjaro","GLP-1/GIP dual","Weekly injection","2.5 mg"]]},{type:"heading",level:3,text:"Dose Titration"},{type:"text",body:"Both medications start at a low dose and are increased gradually every 4 weeks. This approach **minimizes side effects** and lets your body adjust. Do not increase your dose without direction from your provider."},{type:"heading",level:3,text:"Injection Instructions"},{type:"bullets",items:["**Store medication in the refrigerator** (36-46 degrees F). Do not freeze. Once in use, pens can be kept at room temperature (up to 86\xb0F) — **Wegovy for up to 28 days, Ozempic for up to 56 days**.","**Remove from fridge 15-30 minutes** before injecting to reduce discomfort","**Inject once weekly** on the same day each week","**Rotate injection sites** — abdomen, thigh, or upper arm. Use a different spot each week.","**Clean the site** with an alcohol swab before injecting","**Pinch the skin** and insert the needle at a 90-degree angle","**Inject slowly**, then hold the needle in place for 10 seconds before withdrawing","**Dispose of needles** in a sharps container (never in regular trash)"]},{type:"heading",level:3,text:"Missed Dose"},{type:"text",body:"Missed dose rules vary by medication:"},{type:"bullets",items:["**Wegovy (semaglutide for weight loss):** take it as soon as you remember if your next dose is at least 2 days away. Otherwise skip and resume your schedule.","**Ozempic (semaglutide for diabetes):** take it within 5 days of the missed dose. If more than 5 days have passed, skip it.","**For all GLP-1 medications:** never take two doses in the same week.","**Missed 2 or more weeks?** Call our office before restarting — you may need to re-titrate your dose to avoid side effects."]}]},{id:"nutrition",title:"Nutrition Guidelines",content:[{type:"text",body:"GLP-1 medications reduce your appetite, which means **every bite counts**. At Buffington Family Medicine, we use a protein-first approach to ensure you maintain muscle mass and get the nutrients you need from smaller portions."},{type:"callout",variant:"info",title:"Most important nutrition rules",body:"**1. Protein first** at every meal (60-80g/day). **2. Stay hydrated** (64oz water minimum). **3. Eat smaller portions** and stop when satisfied. **4. Eat consistently** — do not skip meals even when appetite is low. **5. Stick with foods you tolerate** — especially in the first few weeks."},{type:"heading",level:3,text:"The Protein-First Rule"},{type:"text",body:"At every meal, **eat your protein first** before moving to vegetables and then carbohydrates. Aim for **60-80 grams of protein per day** minimum. This protects your muscle mass during weight loss."},{type:"heading",level:3,text:"Recommended Foods"},{type:"bullets",items:["**Lean proteins** — chicken breast, turkey, fish, eggs, Greek yogurt, cottage cheese","**Vegetables** — leafy greens, broccoli, bell peppers, zucchini, green beans","**Complex carbs** (small portions) — sweet potatoes, quinoa, brown rice, oatmeal","**Healthy fats** (in moderation) — avocado, olive oil, nuts, seeds","**High-protein snacks** — protein shakes, jerky, string cheese, hard-boiled eggs"]},{type:"heading",level:3,text:"Foods to Limit"},{type:"bullets",items:["**Fried and greasy foods** — these worsen nausea and bloating","**Sugary drinks** — soda, juice, sweetened coffee drinks","**Refined carbs** — white bread, pasta, pastries, chips","**Large portions** — your stomach capacity is reduced; overeating causes discomfort","**Alcohol** — empty calories and can increase nausea (see FAQ below)","**Carbonated beverages** — may increase bloating and gas"]},{type:"heading",level:3,text:"Meal Timing"},{type:"bullets",items:["**Eat 3 small meals** and 1-2 protein-rich snacks per day","**Do not skip meals** — even if your appetite is low, your body needs nutrients","**Stop eating when satisfied** — do not wait until you feel full or uncomfortable","**Avoid eating within 2-3 hours of bedtime** to reduce reflux"]},{type:"callout",variant:"info",title:"Dehydration risk",body:"Reduced appetite often means reduced fluid intake. Set reminders to drink water throughout the day. Aim for at least 64 oz daily. Signs of dehydration include dark urine, dizziness, headache, and fatigue."},{type:"heading",level:3,text:"Healthy Eating Habits"},{type:"bullets",items:["**Keep track of calories and activity level** — awareness is the first step to change","**Use smaller plates, bowls, and glasses** to control portions without feeling deprived","**Don't eat while distracted** — turn off the TV, computer, and phone during meals","**Take 30 minutes for each meal** — eat slowly and wait 20 minutes before getting a second serving","**Ask yourself before eating:** Am I actually hungry? Is this the right food? Am I eating because I'm bored or stressed?"]},{type:"heading",level:3,text:"Stress Eating Alternatives"},{type:"text",body:"If you find yourself reaching for food when you are stressed, anxious, or bored, try one of these instead:"},{type:"bullets",items:["Call a friend or family member","Take a warm bath","Listen to music","Go for a short walk","Do an activity that keeps your hands busy — gardening, puzzles, cleaning"]},{type:"heading",level:3,text:"Calorie Swap Examples"},{type:"text",body:"Small substitutions add up. These swaps save approximately **365 calories per day**:"},{type:"table",headers:["Instead of","Try","Calories Saved"],rows:[["Regular soda (20 oz)","Water or Mio/Crystal Light","~240 cal"],["Ranch dressing (2 tbsp)","Balsamic vinaigrette (2 tbsp)","~100 cal"],["White bread (2 slices)","100% whole wheat (2 slices)","~25 cal"]]},{type:"heading",level:3,text:"Approved Sweeteners"},{type:"text",body:"If you need to sweeten your coffee, tea, or food, these are all acceptable at 0 calories: **Stevia, Truvia, Sweet N' Low,** and **Splenda**."},{type:"heading",level:3,text:"Approved Drinks"},{type:"bullets",items:["Water (always the best choice)","**Mio** or **Crystal Light** (0 cal flavor enhancers)","Black coffee or coffee with a small amount of milk and sugar substitute","Unsweetened tea","Unsweetened almond milk or soy milk"]}]},{id:"food-list",title:"Food List",content:[{type:"text",body:"This is your approved grocery list. All items include calorie counts per serving to help you track your intake. Focus on **lean proteins**, **vegetables**, and **whole grains**."},{type:"heading",level:3,text:"Proteins"},{type:"table",headers:["Food","Serving","Calories"],rows:[["Chicken breast (skinless)","5 oz","~165"],["Turkey breast (skinless)","5 oz","~175"],["Turkey bacon","5 slices","~175"],["Turkey pepperoni","45 slices","~196"],["Lean deli ham","17 thin slices","~198"],["Pork tenderloin","5 oz","~200"],["Extra lean ground beef","3 oz","~151"],["Top sirloin or eye round steak","5 oz","~180"],["Cod","6 oz","~179"],["Jumbo lump crab meat","1 cup","~200"],["Shrimp","31 pieces","~194"],["Starkist tuna (canned)","1 cup","~200"],["Egg whites","9 large","~153"],["Whole egg","1 large","~78"],["Greek yogurt (nonfat)","1 cup","~130"],["Cottage cheese (low-fat)","1 cup","~180"]]},{type:"heading",level:3,text:"Vegetables (mostly unlimited)"},{type:"text",body:"Most non-starchy vegetables are very low calorie. Eat freely:"},{type:"bullets",items:["Leafy greens (spinach, romaine, arugula)","Broccoli, cauliflower, asparagus","Bell peppers, cucumbers, celery","Mushrooms, onions, tomatoes","Green beans, wax beans, snow peas","Collard greens, mustard greens","Sprouts (bean, alfalfa), scallions, jalapenos","Zucchini, squash"]},{type:"heading",level:3,text:"Cereals & Grains"},{type:"table",headers:["Food","Serving","Calories"],rows:[["Steel cut oats","1 cup cooked","~80"],["All Bran Original","1/2 cup","~80"],["Oat Bran cereal","3/4 cup","~150"],["Fiber One cereal","1/2 cup","~60"],["100% whole wheat pasta","3/4 cup cooked","~200"],["Quinoa","1/2 cup cooked","~111"],["Brown rice","1/2 cup cooked","~108"]]},{type:"heading",level:3,text:"Breads"},{type:"bullets",items:["100% whole wheat pita","100% whole wheat stone ground bread","Sugar-free multigrain bread (Oro-Wheat)"]},{type:"heading",level:3,text:"Dairy"},{type:"bullets",items:["Skim milk","Unsweetened almond milk","Unsweetened soy milk","Extra low-fat cheese","Lactose-free creamer (small amounts)"]},{type:"heading",level:3,text:"Fruits (in moderation)"},{type:"table",headers:["Food","Serving","Calories"],rows:[["Raspberries","1 cup","~64"],["Blackberries","1 cup","~62"],["Strawberries","1 cup","~49"],["Cantaloupe","1 cup","~54"],["Peach","1 medium","~59"],["Pear","1 medium","~101"],["Grapes","1 cup","~104"],["Apricot","1 medium","~17"],["Nectarine","1 medium","~63"]]},{type:"heading",level:3,text:"Snacks & Other"},{type:"table",headers:["Food","Serving","Calories"],rows:[["Almonds","2 tbsp","~100"],["Peanuts","2 tbsp","~100"],["Red/white kidney beans or black beans","1/2 cup","~110"],["Sugar-free Jell-O","1 cup","~10"],["Sugar-free popsicle","1 bar","~15"],["Air-popped popcorn","3 cups","~93"],["Kind bar (avoid coconut/yogurt varieties)","1 bar","~200"],["EAS Advantage Shake","1 shake","~160"],["Atkins Advantage Shake","1 shake","~160"]]},{type:"heading",level:3,text:"Condiments & Spices"},{type:"bullets",items:["Balsamic or raspberry vinaigrette (instead of ranch/cream-based)","Mustard (0 cal)","Low-fat spray butter","Spice blends: Garlic Salt, Lemon Pepper, Lawry's Seasoned Salt, Emeril's Italian Essence"]}]},{id:"meal-plans",title:"Sample Meal Plans",content:[{type:"text",body:"These are sample daily meal plans to give you practical ideas. Each plan emphasizes **protein first**, whole foods, and realistic portions. Mix and match to suit your preferences."},{type:"heading",level:3,text:"Meal Plan 1"},{type:"bullets",items:["**Breakfast:** 3 egg whites + 1 whole egg scrambled with spinach and salsa","**Lunch:** Grilled chicken salad with mixed greens, cucumbers, tomatoes, and balsamic vinaigrette","**Snack:** Greek yogurt with raspberries","**Dinner:** Baked cod (6 oz) with steamed broccoli and 1/2 cup brown rice"]},{type:"heading",level:3,text:"Meal Plan 2"},{type:"bullets",items:["**Breakfast:** Steel cut oatmeal with blackberries and a scoop of protein powder","**Lunch:** Turkey lettuce wraps with mustard, tomato, and cucumber","**Snack:** String cheese and almonds (2 tbsp)","**Dinner:** Skinless roasted chicken (3 oz diced) with quinoa and green beans"]},{type:"heading",level:3,text:"Meal Plan 3"},{type:"bullets",items:["**Breakfast:** Whole wheat pita with 2 scrambled eggs and a slice of low-fat cheese","**Lunch:** Tuna salad (canned tuna, mustard, celery, onion) on whole wheat bread","**Snack:** Cottage cheese with strawberries","**Dinner:** Shrimp stir-fry with bell peppers, snap peas, and a splash of soy sauce over cauliflower rice"]},{type:"heading",level:3,text:"Meal Plan 4"},{type:"bullets",items:["**Breakfast:** Protein shake (EAS or Atkins) blended with ice and a handful of spinach","**Lunch:** Chicken burger (no bun) with lettuce, tomato, mustard, and a side salad","**Snack:** Hard-boiled eggs (2) with everything seasoning","**Dinner:** Pork tenderloin (5 oz) with roasted asparagus and sweet potato (small)"]},{type:"heading",level:3,text:"Meal Plan 5"},{type:"bullets",items:["**Breakfast:** Coffee with milk and sugar substitute + Whole Grain Wasa crackers with cottage cheese","**Lunch:** Deli ham roll-ups with mustard, lettuce, and a cup of broth-based soup","**Snack:** Air-popped popcorn (3 cups)","**Dinner:** Top sirloin steak (5 oz) with steamed zucchini and mushrooms"]},{type:"callout",variant:"info",title:"Tip",body:"These are starting points — not rigid rules. The key principles are: **protein first at every meal**, plenty of vegetables, limited refined carbs, and staying hydrated. Adjust portions based on your appetite and your provider's guidance."}]},{id:"vitamins",title:"Vitamins & Supplements",content:[{type:"text",body:"When you are eating less food, you are also getting fewer vitamins and minerals. Supplementation helps prevent deficiencies that can slow your progress and affect your health."},{type:"heading",level:3,text:"Daily Multivitamin"},{type:"text",body:"Take a daily multivitamin. **Capsule form absorbs better than hard tablets.** Liquid or powder forms absorb even better but can be harder to tolerate taste-wise. Avoid gummy vitamins — they often contain added sugar and lower nutrient amounts."},{type:"heading",level:3,text:"B-Complex (including B12)"},{type:"text",body:"We recommend a **B-complex** supplement rather than B12 alone. You need at least **1,000 mcg/day of B12**. B12 deficiency causes anemia and can cause neurologic and psychiatric conditions."},{type:"bullets",items:["**Signs of B12 deficiency:** fatigue, numbness/tingling, difficulty losing weight, memory loss, confusion","**Target B12 level:** above 400 pg/mL (above **600 pg/mL** for optimal weight loss)"]},{type:"heading",level:3,text:"Vitamin D + Calcium"},{type:"text",body:"Recommended for everyone over 30 and anyone actively losing weight. Weight loss can decrease bone density, so calcium and vitamin D are especially important."},{type:"bullets",items:["**Vitamin D:** at least **800 IU per day**. Target blood level above 30 ng/mL (above **60 ng/mL** for optimal weight loss)","**Calcium:** at least **1,200 mg per day**. Note: blood calcium levels are unreliable because your body pulls calcium from bones to maintain blood levels"]},{type:"heading",level:3,text:"Brand Recommendations"},{type:"callout",variant:"info",title:"Not all vitamins are created equal",body:"Over 10 years of practice, we have found that most vitamin brands do not get absorbed well enough to change blood levels — which means they are a waste of time and money. The brands we recommend based on results in our patients are **Pure Encapsulations** and **GNC**. Pure Encapsulations uses higher quality ingredients without filler that can irritate the stomach."}]},{id:"exercise",title:"Exercise Plan",content:[{type:"text",body:"Regular physical activity **preserves muscle mass**, improves mood, and helps maintain your weight loss long-term. You do not need to do intense workouts — consistency matters more than intensity."},{type:"heading",level:3,text:"Weekly Goal: 150 Minutes"},{type:"text",body:"Aim for at least **150 minutes of moderate activity per week** (about 30 minutes on 5 days). Alternatively, **75 minutes of vigorous activity per week** achieves similar benefits."},{type:"text",body:"Start where you are and build up gradually. **Consult your provider before starting a new exercise program.**"},{type:"heading",level:3,text:"Moderate vs. Vigorous"},{type:"text",body:"A simple test: during **moderate** exercise, you can still carry on a conversation. During **vigorous** exercise, you are too out of breath to talk comfortably."},{type:"table",headers:["Moderate Activities","Vigorous Activities"],rows:[["Walking briskly (15-min mile)","Jogging or running"],["Light yard work","Swimming laps"],["Biking under 10 mph","Biking over 10 mph"],["Golf (walking + carrying clubs)","Jumping rope"],["Dancing","Rollerblading"],["Light snow shoveling","High-intensity interval training"]]},{type:"heading",level:3,text:"Recommended Activities"},{type:"bullets",items:["**Walking** — the easiest way to start. Aim for 30 minutes most days.","**Swimming or water aerobics** — low-impact and easy on joints","**Cycling** — stationary or outdoor, great for cardiovascular fitness","**Yoga or stretching** — improves flexibility and reduces stress","**YouTube workout videos** — free and can be done at home with no equipment"]},{type:"heading",level:3,text:"Strength Training Is Essential"},{type:"text",body:"When you lose weight, you lose both fat and muscle. **Strength training 2-3 times per week** helps preserve muscle mass, keeps your metabolism healthy, and improves body composition. You can use bodyweight exercises, resistance bands, or light weights."},{type:"heading",level:3,text:"Daily Movement Checklist"},{type:"checklist",items:["Take a 10-15 minute walk after at least one meal","Stand up and move for 2-3 minutes every hour","Take the stairs instead of the elevator when possible","Park farther away from entrances","Do 5-10 minutes of stretching in the morning or evening"]},{type:"callout",variant:"info",title:"Start slow",body:"If you have not been exercising regularly, start with 10-15 minute walks and increase gradually. Start with **3-pound dumbbells** for strength training. Listen to your body, especially during the first few weeks on medication when your calorie intake is lower."},{type:"heading",level:3,text:"What's Holding You Back?"},{type:"bullets",items:['**"I don\'t have time"** — Start with 10-minute walks. Three 10-minute walks equals your 30 minutes. Take the stairs, park farther away, walk during phone calls.','**"I have no energy"** — Exercise actually increases your energy. Start small and you will notice the difference within days.','**"I\'m too out of shape"** — Everyone starts somewhere. Walking is exercise. There is no minimum fitness level required.',"**\"I can't afford a gym\"** — You don't need one. Walk outside, do bodyweight exercises at home, follow free YouTube workout videos.",'**"It\'s hard to get started"** — Set a non-food reward for reaching your first goal (new clothes, an outing). Track your daily activity and celebrate progress in a journal.']}]},{id:"milestones",title:"Your Milestones",content:[{type:"text",body:"Weight loss on GLP-1 medications is gradual and steady. Here is what to expect at each stage of your program."},{type:"milestone",week:"Week 1",title:"Getting Started",details:["First injection taken at starting dose","Appetite may begin to decrease within a few days","Some patients notice mild nausea — this is normal and usually passes","Begin tracking meals and water intake","Weigh yourself on day 1 to establish your baseline"]},{type:"milestone",week:"Weeks 2-3",title:"Adjusting",details:["Appetite reduction becomes more noticeable","You may start eating smaller portions naturally","Early side effects (nausea, mild fatigue) often begin to improve","Focus on hitting your daily protein and water goals","Scale weight may fluctuate — this is normal early on"]},{type:"milestone",week:"Month 1",title:"First Follow-Up",details:["4-week office visit with your provider","Review your weight, side effects, and overall response","Provider may increase your dose based on tolerance","Typical weight loss at this stage: **3-6 lbs**","Labs may be checked if indicated"]},{type:"milestone",week:"Months 2-3",title:"Building Momentum",details:["Weight loss becomes more consistent as dose increases","Typical cumulative loss: **8-15 lbs** (varies by individual)","Side effects generally improve as your body adjusts","Nutrition and exercise habits become routine","Monthly follow-ups continue to track progress"]},{type:"milestone",week:"Months 4-6",title:"Steady Progress",details:["Approaching maintenance dose for most patients","Typical cumulative loss: **15-25+ lbs** (varies by individual)","Follow-up visits may transition to every 2-3 months","Lab work reassessed (metabolic panel, A1C if applicable)","Discussion of long-term maintenance plan begins"]}]},{id:"side-effects",title:"Side Effects & Management",content:[{type:"callout",variant:"urgent",title:"Thyroid cancer warning (FDA black box)",body:"GLP-1 medications carry an FDA black box warning for **thyroid C-cell tumors**. This risk has been observed in animal studies. GLP-1 medications are **contraindicated** in patients with a personal or family history of **medullary thyroid carcinoma (MTC)** or **Multiple Endocrine Neoplasia syndrome type 2 (MEN2)**. Contact our office immediately if you develop a **lump or swelling in your neck**, **trouble swallowing**, **hoarseness**, or **shortness of breath**."},{type:"text",body:"Side effects are most common during the first few weeks and after dose increases. Most are **mild and temporary**. Below they are organized by severity so you know what to expect and when to reach out."},{type:"heading",level:3,text:"Common & Expected (usually resolve on their own)"},{type:"bullets",items:["**Nausea** — the most common side effect, usually improves within 1-2 weeks","**Constipation** — due to slowed digestion; increase water and fiber intake","**Diarrhea** — less common; usually mild and self-resolving","**Bloating or gas** — eat smaller meals and avoid carbonated drinks","**Fatigue** — often related to reduced calorie intake; ensure adequate protein","**Headache** — usually related to dehydration; drink more water","**Injection site reactions** — mild redness or itching; rotate sites weekly"]},{type:"heading",level:3,text:"Call Our Office Soon"},{type:"bullets",items:["**Persistent nausea or vomiting** that does not improve after 1-2 weeks or worsens","**Mood changes** — new or worsening depression, anxiety, irritability, or agitation","**Thoughts of self-harm** — contact our office immediately or call 988 (Suicide & Crisis Lifeline)","**Constipation lasting more than a week** despite water, fiber, and over-the-counter remedies","**Unable to eat or drink enough** — if you cannot meet basic nutrition needs for more than a day"]},{type:"heading",level:3,text:"Urgent — Stop Medication and Call Immediately"},{type:"bullets",items:["**Severe abdominal pain** — especially upper abdominal pain radiating to the back (possible pancreatitis)","**Severe or persistent vomiting** with chills, fever, or lightheadedness","**Signs of allergic reaction** — swelling of face/throat, difficulty breathing, rash or hives","**Lump or swelling in your neck**, trouble swallowing, or hoarseness","**Unable to keep food or liquids down** for more than 24 hours"]},{type:"callout",variant:"urgent",title:"Our office number",body:"Call **(817) 431-9199** for any side effect questions or concerns. Our team is here to help — do not hesitate to reach out."},{type:"heading",level:3,text:"Managing Nausea"},{type:"bullets",items:["Eat smaller, more frequent meals throughout the day","Avoid fried, greasy, or very rich foods","Eat bland foods when nausea is worst (crackers, toast, broth, bananas)","Stay hydrated — sip water, ginger tea, or clear broth","Avoid lying down immediately after eating","Take your injection at bedtime so nausea peaks while you sleep","Ask your provider about anti-nausea medication if needed"]},{type:"heading",level:3,text:"Managing Constipation"},{type:"bullets",items:["Drink at least 64 oz of water per day","Increase fiber intake gradually (vegetables, berries, chia seeds)","Take a daily walk — movement stimulates digestion","Over-the-counter MiraLAX or docusate may help (ask your provider)","Avoid relying on stimulant laxatives long-term"]},{type:"heading",level:3,text:"Surgery & Anesthesia"},{type:"text",body:"GLP-1 medications slow stomach emptying, which increases the risk of **pulmonary aspiration** during surgery or procedures using anesthesia or sedation."},{type:"text",body:"**Always tell your surgeon and anesthesiologist that you are taking a GLP-1 medication.** Your provider may instruct you to stop the medication before a scheduled procedure — ask us if you have any upcoming surgeries."},{type:"heading",level:3,text:"Gastroparesis"},{type:"text",body:"GLP-1 medications are **not recommended** for patients with severe gastroparesis. Because these medications further slow gastric emptying, they can significantly worsen gastroparesis symptoms. If you have been diagnosed with gastroparesis, discuss this with your provider before starting treatment."}]},{id:"common-mistakes",title:"Common Mistakes to Avoid",content:[{type:"text",body:"After working with hundreds of weight loss patients, our team at Buffington Family Medicine sees the same patterns that slow people down. Avoiding these common mistakes will help you get better results."},{type:"bullets",items:["**Not eating enough protein** — This is the #1 mistake. When your appetite drops, it is tempting to eat whatever is easiest, but skipping protein leads to muscle loss and a slower metabolism.","**Not drinking enough water** — Dehydration causes fatigue, headaches, constipation, and can stall weight loss. Set reminders and keep water with you.","**Skipping meals** — Your body still needs fuel even when your appetite is low. Small, protein-rich meals keep your energy up and your metabolism running.","**Quitting too early** — The first few weeks can be uncomfortable as your body adjusts. Side effects usually improve. Give the medication time to work before deciding it is not for you.","**Comparing your results to others** — Everyone responds differently. Someone else's timeline is not yours. Focus on your own progress.","**Relying on the medication alone** — The medication is a powerful tool, but lasting results come from building sustainable nutrition and exercise habits alongside it."]},{type:"callout",variant:"info",title:"Remember",body:"If you are struggling with any of these, bring it up at your next visit. Our team is here to help you adjust your plan — not to judge. The patients who do best are the ones who communicate openly with their provider."}]},{id:"plateau",title:"Weight Loss Plateaus",content:[{type:"callout",variant:"info",title:"Plateaus are normal",body:"Nearly everyone hits a weight loss plateau at some point. This does **not** mean the medication has stopped working. Your body is adjusting to its new weight, and with the right adjustments, you will start losing again. Many patients plateau for 2-4 weeks before the scale moves."},{type:"heading",level:3,text:"First Things to Check"},{type:"numbered",items:["**Are you hitting your protein goal?** Aim for 60-80+ grams per day","**Are you drinking enough water?** Dehydration can stall weight loss","**Have your portions crept up?** Track your food for a few days to find out","**Are you moving enough?** Even adding a daily walk can make a difference","**How is your sleep?** Poor sleep raises cortisol and hinders fat loss"]},{type:"heading",level:3,text:"Why Plateaus Happen"},{type:"bullets",items:["**Metabolic adaptation** — as you weigh less, your body needs fewer calories","**Muscle loss** — if not doing strength training, lost muscle reduces your resting metabolic rate","**Portion creep** — over time, meal portions may gradually increase without you noticing","**Water retention** — hormonal fluctuations, sodium, and stress can temporarily mask fat loss"]},{type:"heading",level:3,text:"Strategies to Break Through"},{type:"numbered",items:["**Increase protein** — aim for the higher end of your protein goal (80+ grams/day)","**Add strength training** — building muscle raises your metabolism","**Change your exercise routine** — try a new activity or increase intensity","**Manage stress and sleep** — cortisol and poor sleep both hinder fat loss","**Talk to your provider** — a dose adjustment may help you past a plateau"]},{type:"callout",variant:"info",title:"Look beyond the scale",body:"Focus on how your clothes fit, your energy levels, and your overall health — the scale is only one measure of progress. Body composition changes (losing fat and gaining muscle) can happen even when the scale does not move."}]}],faqs:[{question:"How fast will I lose weight?",answer:"Most patients lose 3-6 lbs in the first month and 1-2 lbs per week after that once on an effective dose. Results vary based on starting weight, dose, diet, and exercise. In clinical trials, patients on GLP-1 medications combined with lifestyle changes lost approximately **15-22% of total body weight** over 12-18 months — roughly 3-18% more than patients using lifestyle changes alone."},{question:"Does the injection hurt?",answer:"Most patients describe it as a small pinch or slight sting. The needle is very thin. Letting the medication come to room temperature before injecting and rotating sites weekly both help reduce discomfort."},{question:"Can I drink alcohol on this medication?",answer:"Alcohol is not prohibited, but we recommend limiting it. Alcohol adds empty calories, can worsen nausea, and may lower your blood sugar. If you choose to drink, start with small amounts to see how your body responds and avoid drinking on an empty stomach."},{question:"What if I miss a dose?",answer:"Take it as soon as you remember if your next dose is more than 2 days away. If less than 2 days until your next scheduled dose, skip the missed one and resume your normal schedule. Never double up or take two doses in the same week."},{question:"Will I gain the weight back if I stop the medication?",answer:"Studies show that many patients regain some weight after stopping GLP-1 medications. The best way to maintain your results is to build sustainable nutrition and exercise habits while on the medication. Your provider will discuss a long-term maintenance plan with you."},{question:"Does insurance cover these medications?",answer:"Coverage varies by plan. Some commercial insurance plans cover Wegovy or Zepbound for weight loss. Our office can help with prior authorizations. Keep in mind that insurance may initially say a medication is covered, but the pharmacy may find it is only covered for diabetes, not weight loss — so always verify the specific indication with your plan."},{question:"My insurance says my medication is covered but the pharmacy says it's not — what happened?",answer:"This is very common. Medications like Ozempic and Mounjaro are approved for diabetes. Wegovy and Zepbound are approved for weight loss. Even though they contain the same active ingredient, they are not interchangeable for insurance purposes. Your insurance may cover the diabetes version but not the weight loss version. Always clarify with your insurance whether the specific medication is covered for weight loss."},{question:"Can you just say I have diabetes so insurance covers it?",answer:"No. We cannot falsify a diagnosis. If you do not have diabetes, we cannot prescribe a diabetes-only medication or submit a diabetes diagnosis to your insurance. This would be insurance fraud."},{question:"How does the prior authorization process work?",answer:"Prior authorization is initiated by the pharmacy, not our office. When you try to fill your prescription, the pharmacy sends us a form. We review your chart and answer their questions, then submit it to your insurance company. This process takes an average of 48-72 business hours from start to finish."},{question:"My insurance has a 'plan exclusion' for weight loss medications — what does that mean?",answer:"A plan exclusion means your pharmacy benefits specifically do not cover weight loss medications. Unfortunately, plan exclusions cannot be appealed — it is a fundamental coverage decision by the plan, not a case-by-case denial."},{question:"The pharmacy says my medication is not in stock — can you help?",answer:"Unfortunately, we cannot view pharmacy inventory. There are national shortages on some weight loss medications. You will need to call your pharmacy directly or try other pharmacies in your area. You can also ask your pharmacy to notify you when it comes back in stock."},{question:"Can I transfer my prescription to a different pharmacy?",answer:"Yes. Contact your current pharmacy or use their app to request a transfer. You can also call the new pharmacy and they can pull the prescription over. You do not need to contact our office for this."},{question:"Do you recommend a specific pharmacy?",answer:"We do not work with or recommend any specific pharmacy. You are welcome to use whichever pharmacy is most convenient for you."},{question:"Do I have to exercise?",answer:"Exercise is not strictly required for weight loss on GLP-1 medications, but it is strongly recommended. Regular activity — especially strength training — preserves muscle mass, improves your metabolism, and helps you maintain weight loss long-term. Even daily walking makes a meaningful difference."},{question:"How much protein do I need?",answer:"We recommend 60-80 grams of protein per day minimum. Because your overall food intake decreases on this medication, making protein the priority at every meal helps prevent muscle loss. Good sources include chicken, fish, eggs, Greek yogurt, and protein shakes."},{question:"How do I manage nausea?",answer:"Eat smaller, more frequent meals. Avoid greasy or fried foods. Stay hydrated. Try bland foods like crackers, toast, or broth when nausea is worst. Taking your injection at bedtime can help. If nausea is severe or persistent, call our office — we can prescribe anti-nausea medication or adjust your dose."},{question:"What helps with constipation?",answer:"Drink at least 64 oz of water daily, increase fiber gradually (vegetables, berries, chia seeds), and stay physically active. Over-the-counter MiraLAX or docusate sodium can help. Avoid stimulant laxatives long-term. If constipation persists, let your provider know."},{question:"Will this medication interact with my other prescriptions?",answer:"GLP-1 medications can affect how quickly other oral medications are absorbed because they slow gastric emptying. Let your provider know about all medications you take. This is especially important for oral contraceptives, blood thinners, and diabetes medications."},{question:"How do I travel with my medication?",answer:"Keep the medication in a cooler bag with ice packs during travel — do not let it freeze or get above 86 degrees F. Pens in use can be stored at room temperature: **Wegovy up to 28 days**, **Ozempic up to 56 days** (check your specific medication's packaging). Carry it in your carry-on bag when flying. Bring a copy of your prescription."},{question:"Can I take this medication if I am trying to get pregnant?",answer:"GLP-1 medications should be stopped at least 2 months before a planned pregnancy. These medications are not recommended during pregnancy or breastfeeding. If you become pregnant while on this medication, stop taking it and contact our office right away."},{question:"Can I switch between semaglutide and tirzepatide?",answer:"Yes, switching is possible and sometimes recommended if you are not responding well to one medication or experiencing significant side effects. Your provider will determine the appropriate starting dose on the new medication. There may be a brief adjustment period."},{question:"What happens when I reach my goal weight?",answer:"Once you reach your goal, your provider will discuss a maintenance plan. This may include continuing on a lower maintenance dose, transitioning off the medication gradually, or other strategies. The lifestyle habits you build during the program — nutrition, exercise, and mindful eating — are key to keeping the weight off."}],resources:[{title:"Injection Instructions Guide",description:"Step-by-step injection instructions with diagrams for semaglutide and tirzepatide pens.",type:"pdf"},{title:"Nutrition Quick Reference",description:"One-page printable guide with protein-first meal ideas, portion guidelines, and hydration tips.",type:"pdf"},{title:"Meal Planning Template",description:"Weekly meal planning template designed for high-protein, reduced-portion eating.",type:"link",url:"#"},{title:"Exercise Starter Guide",description:"Beginner-friendly exercise plan with walking schedules, bodyweight exercises, and weekly goals.",type:"link",url:"#"}],updates:[{title:"Tirzepatide Now Available at Lower Cost",date:"2026-03-22",summary:"New manufacturer savings programs have reduced out-of-pocket costs for Zepbound. Ask our office about eligibility at your next visit."},{title:"Updated Protein Guidelines",date:"2026-03-15",summary:"Based on recent research, we have increased our minimum daily protein recommendation to 60-80 grams for patients on GLP-1 medications to better protect muscle mass."},{title:"Spring Walking Challenge",date:"2026-03-08",summary:"Join our 30-day walking challenge starting April 1. Aim for 8,000 steps per day and track your progress. Ask the front desk for details at your next appointment."}],nextSteps:[{title:"Schedule Follow-Up",description:"Book your next weight loss check-in with your provider.",action:"Schedule Now",href:"tel:8174319199"},{title:"Contact Our Office",description:"Questions about your medication, side effects, or program? We are here to help.",action:"Call (817) 431-9199",href:"tel:8174319199"},{title:"Request Refill",description:"Patients must be seen every 4 weeks to get their medication refilled. Schedule your appointment before you run out so there is no gap in your treatment.",action:"Request Refill",href:"tel:8174319199"},{title:"Message Provider",description:"Send a non-urgent message to your provider through the patient portal.",action:"Open Portal",href:"#"}]};function r(){return(0,a.jsx)(o.Suspense,{children:(0,a.jsx)(s.oP,{config:n})})}}},function(e){e.O(0,[197,115,364,744],function(){return e(e.s=9021)}),_N_E=e.O()}]);